// src/components/shared/NexusLogo.js
// Transparent logo — white background removed
const LOGO_B64 = "data:image/png;base64,";

export default function NexusLogo({ size = 32, style = {} }) {
  return (
    <img
      src={LOGO_B64}
      alt="Nexus"
      width={size}
      height={size}
      style={{ objectFit: "contain", display: "block", ...style }}
    />
  );
}
